# 1400줄이 넘는 코드를 처리하기 위해 모든 카드의 meanings를 meanings_db 값으로 업데이트
def replacer(match):
    json_str = match.group(1)
    try:
        data = json.loads(json_str)
    except Exception as e:
        print(f"JSON Parsing Error: {e}")
        return match.group(0)
    
    for item in data:
        cid = item["id"]
        if cid in meanings_db:
            # Celestial 스타일 가이드에 맞춰 meanings 필드 교체
            item["meanings"] = meanings_db[cid]
            
    # 한국어 인코딩 깨짐 방지 및 들여쓰기 유지
    new_json_str = json.dumps(data, ensure_ascii=False, indent=2)
    return "const tarotDataKo = " + new_json_str + ";"

print("Reading data_ko.js...")
with codecs.open(data_file, 'r', 'utf-8') as f:
    content = f.read()

# 정규표현식으로 const tarotDataKo 부분 탐색
new_content = re.sub(r'const tarotDataKo\s*=\s*(\[\s*\{.*?\}\s*\]);', replacer, content, flags=re.DOTALL)

print("Writing updated content to data_ko.js...")
with codecs.open(data_file, 'w', 'utf-8') as f:
    f.write(new_content)

print(f"Success! All 78 cards have been updated with Celestial-styled meanings.")
